import React, { useState } from 'react';
import Home from './pages/Home';
import Login from './pages/Login';
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  const [currentPage, setCurrentPage] = useState('home');

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#f8f9fa' }}>

      {/* --- Varcha Blue Bar (Navbar) START --- */}
      <nav className="navbar navbar-expand-lg navbar-dark px-4 shadow" style={{ backgroundColor: '#0056b3' }}>
        <div className="container-fluid">
          <span 
            className="navbar-brand fw-bold fs-3" 
            style={{ cursor: 'pointer', letterSpacing: '1px' }} 
            onClick={() => setCurrentPage('home')}
          >
            APNI MANZIL
          </span>

          <div className="ms-auto">
            {currentPage === 'home' ? (
              <button 
                onClick={() => setCurrentPage('login')} 
                className="btn btn-success rounded-pill px-4 fw-bold shadow-sm"
              >
                Login / Sign Up
              </button>
            ) : (
              <button 
                onClick={() => setCurrentPage('home')} 
                className="btn btn-light rounded-pill px-4 fw-bold shadow-sm"
              >
                ← Back to Home
              </button>
            )}
          </div>
        </div>
      </nav>
      {/* --- Varcha Blue Bar (Navbar) END --- */}

      {/* Main Content */}
      <main>
        {currentPage === 'home' ? <Home /> : <Login />}
      </main>

      <footer className="text-center py-4 text-muted small mt-5">
        © 2026 Apni Manzil | All-in-One Logistics Solution
      </footer>
    </div>
  );
}

export default App;
